def calculate_seat_percentages(election_results):
    total_seats = 47
    seat_percentages = {party: (seats / total_seats) * 100 
                        for party, seats in election_results.items()}
    return seat_percentages

# Example usage:
results = {"PSD": 19, "PS": 12, "PP": 3, "JPP": 2, "CDU": 1}
print(calculate_seat_percentages(results))
# Output: {'PSD': 40.43, 'PS': 25.53, 'PP': 6.38, 'JPP': 4.26, 'CDU': 2.13}
